$json = Get-Content "C:\Users\ryanc\projects\outlook_rwa\chat_session.json" -Raw | ConvertFrom-Json

# Get user messages to understand what was asked
$userMsgs = $json | Where-Object { $_.message -and $_.message.role -eq "user" }
$userMsgs | ForEach-Object {
    $content = $_.message.content
    if ($content -is [string]) {
        $preview = $content.Substring(0, [Math]::Min(300, $content.Length))
        Write-Host "=== USER ==="
        Write-Host $preview
        Write-Host ""
    }
} | Select-Object -First 30

$json = Get-Content "C:\Users\ryanc\projects\outlook_rwa\chat_session.json" -Raw | ConvertFrom-Json

# Get assistant messages with text content
$assistantMsgs = $json | Where-Object { $_.message -and $_.message.role -eq "assistant" }
$count = 0
foreach ($msg in $assistantMsgs) {
    $content = $msg.message.content
    if ($content -is [array]) {
        foreach ($block in $content) {
            if ($block.type -eq "text" -and $block.text) {
                $preview = $block.text.Substring(0, [Math]::Min(500, $block.text.Length))
                Write-Host "=== ASSISTANT ==="
                Write-Host $preview
                Write-Host ""
                $count++
                if ($count -ge 6) { return }
            }
        }
    }
}

$json = Get-Content "C:\Users\ryanc\projects\outlook_rwa\chat_session.json" -Raw | ConvertFrom-Json

# Get the LAST assistant messages to understand current state
$assistantMsgs = $json | Where-Object { $_.message -and $_.message.role -eq "assistant" }
$lastMsgs = $assistantMsgs | Select-Object -Last 5
foreach ($msg in $lastMsgs) {
    $content = $msg.message.content
    if ($content -is [array]) {
