            if ($block.type -eq "text" -and $block.text) {
                $preview = $block.text.Substring(0, [Math]::Min(800, $block.text.Length))
                Write-Host "=== ASSISTANT (recent) ==="
                Write-Host $preview
                Write-Host ""
            }
        }
    }
}

$json = Get-Content "C:\Users\ryanc\projects\outlook_rwa\chat_session.json" -Raw | ConvertFrom-Json

# Get all entries in order, find last few user + assistant messages
$msgs = $json | Where-Object { $_.message -and ($_.message.role -eq "user" -or $_.message.role -eq "assistant") }
$last = $msgs | Select-Object -Last 10

foreach ($msg in $last) {
    $role = $msg.message.role.ToUpper()
    $content = $msg.message.content
    if ($content -is [string]) {
        $preview = $content.Substring(0, [Math]::Min(400, $content.Length))
        Write-Host "=== $role ==="; Write-Host $preview; Write-Host ""
    } elseif ($content -is [array]) {
        foreach ($block in $content) {
            if ($block.type -eq "text" -and $block.text) {
                $preview = $block.text.Substring(0, [Math]::Min(400, $block.text.Length))
                Write-Host "=== $role ==="; Write-Host $preview; Write-Host ""
            }
        }
    }
}

$json = Get-Content "C:\Users\ryanc\projects\outlook_rwa\chat_session.json" -Raw | ConvertFrom-Json

# Get all message entries (user and assistant), in order
$msgs = $json | Where-Object { $_.message -and ($_.message.role -eq "user" -or $_.message.role -eq "assistant") }
$last15 = $msgs | Select-Object -Last 15

foreach ($msg in $last15) {
    $role = $msg.message.role.ToUpper()
    $content = $msg.message.content
    if ($content -is [string]) {
        Write-Host "=== $role ===`n$($content.Substring(0, [Math]::Min(600, $content.Length)))`n"
    } elseif ($content -is [array]) {
        foreach ($block in $content) {
            if ($block.type -eq "text" -and $block.text) {
                Write-Host "=== $role ===`n$($block.text.Substring(0, [Math]::Min(600, $block.text.Length)))`n"
            }
        }
    }
}

$json = Get-Content "C:\Users\ryanc\projects\outlook_rwa\chat_session.json" -Raw | ConvertFrom-Json

# Show all entry types in last 30 entries
$last30 = $json | Select-Object -Last 30
foreach ($entry in $last30) {
    $type = $entry.type
    $role = if ($entry.message) { $entry.message.role } else { "" }
    $label = if ($role) { "$type/$role" } else { $type }

    $content = ""
    if ($entry.message -and $entry.message.content) {
        $c = $entry.message.content
        if ($c -is [string]) { $content = $c.Substring(0, [Math]::Min(500, $c.Length)) }
        elseif ($c -is [array]) {
            foreach ($b in $c) {
                if ($b.type -eq "text" -and $b.text) {
                    $content += $b.text.Substring(0, [Math]::Min(500, $b.text.Length))
                }
            }
        }
    } elseif ($entry.content) {
        $content = $entry.content.Substring(0, [Math]::Min(300, $entry.content.Length))
    }

    Write-Host "[$label]"
    if ($content) { Write-Host $content }
    Write-Host ""
}

$json = Get-Content "C:\Users\ryanc\projects\outlook_rwa\chat_session.json" -Raw | ConvertFrom-Json

# Find the assistant message that starts with "Good catches"
foreach ($entry in $json) {
    if ($entry.message -and $entry.message.role -eq "assistant" -and $entry.message.content -is [array]) {
        foreach ($block in $entry.message.content) {
            if ($block.type -eq "text" -and $block.text -and $block.text.StartsWith("Good catches")) {
                Write-Host $block.text
                Write-Host "--- END ---"
            }
        }
    }
}
